href=\"https://profiles.wordpress.org/traxus/\">traxus</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/sllimrovert/\">Trevor Mills</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/tristanleboss/\">tristanleboss</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/areziaal/\">Troy Chaplin</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/truptikanzariya/\">Trupti Kanzariya</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/tsteel/\">tsteel</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/dinhtungdu/\">Tung Du</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/tusharbharti/\">Tushar Bharti</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/tusharaddweb/\">Tushar Patel</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/tussendoor/\">Tussendoor BV</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/ugyensupport/\">Ugyen Dorji</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/umeshnevase/\">Umesh Nevase</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/umeshsinghin/\">Umesh Singh</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/unsalkorkmaz/\">Unsal Korkmaz</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/upadalavipul/\">upadalavipul</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/utsavladani/\">Utsav Ladani</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/utsav72640/\">Utsav tilava</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/valentingrenier/\">Valentin Grenier</a>&nbsp;·<a href=\"https://profiles.wordpress.org/tsimshatsui/\">Vape tsimshatsui</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/vbbp/\">vbbp</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/sheldorofazeroth/\">Vedansh Mishra</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/vevas/\">Vegard S.</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/vgnavada/\">vgnavada</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/vcanales/\">Vicente Canales</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/vidugupta/\">vidugupta</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/vijendrajat/\">Vijendra Jat</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/szepeviktor/\">Viktor Szépe</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/vineet2003/\">Vinit</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/ghorivipul97/\">Vipul Ghori</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/vipulgupta003/\">Vipul Gupta</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/vipulpatil/\">Vipul Patil</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/vishitshah/\">Vishit Shah</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/vladimiraus/\">vladimiraus</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/vortfu/\">vortfu</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/vrishabhsk/\">Vrishabh Jasani</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/walterebert/\">Walter Ebert</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/webmandesign/\">WebMan Design | Oliver Juhas</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/websupporter/\">websupporter</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/webwrotter/\">webwrotter</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/westonruter/\">Weston Ruter</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/whaze/\">whaze</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/widhy980/\">widhy980</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/skorasaurus/\">Will Skora</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/wplmillet/\">wplmillet</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/xate/\">xate</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/xavilc/\">xavilc</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/xerpa43/\">xerpa43</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/xipasduarte/\">xipasduarte</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/yagniksangani/\">Yagnik Sangani</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/yashyadav247/\">Yash</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/getsyash/\">Yash B</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/yashjawale/\">Yash Jawale</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/yogeshbhutkar/\">Yogesh Bhutkar</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/yogieanamcara/\">YogieAnamCara</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/fierevere/\">Yui</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/zebulan/\">Zebulan Stanphill</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/zeelthakkar/\">Zeel Thakkar</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/zunaid321/\">Zunaid Amin</a>&nbsp;·&nbsp;<a href=\"https://profiles.wordpress.org/lstraczynski/\">Łukasz Strączyński</a>&nbsp;·<a href=\"https://profiles.wordpress.org/haozi/\">耗子</a></p>\n\n\n\n<p class=\"wp-block-paragraph\">Más de <a href=\"https://translate.wordpress.org/stats/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">71 equipos locales han traducido</a> WordPress 6.9 a su idioma. Los traductores de la comunidad están trabajando arduamente para garantizar que haya más traducciones en camino. Gracias a todos los que ayudan a que WordPress esté disponible en más de 200 idiomas.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Por último, pero no menos importante, gracias a los voluntarios que contribuyen a los <a href=\"https://es.wordpress.org/support/forums/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">foros de soporte</a> respondiendo preguntas de los usuarios de WordPress de todo el mundo.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Implícate</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">Participar en WordPress va mucho más allá de programar. Aprender más y participar es fácil. Descubre los equipos que se unen para <a href=\"https://make.wordpress.org/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">crear WordPress</a> y usa <a href=\"https://make.wordpress.org/contribute/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">esta herramienta interactiva</a> para ayudarte a decidir cuál es el más adecuado para ti.</p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"https://es.wordpress.org/2025/12/03/wordpress-6-9-gene/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"740325\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"WordPress Day Sevilla 2025: Los custodios del saber digital\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:95:\"https://es.wordpress.org/2025/11/26/wordpress-day-sevilla-2025-los-custodios-del-saber-digital/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:103:\"https://es.wordpress.org/2025/11/26/wordpress-day-sevilla-2025-los-custodios-del-saber-digital/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 26 Nov 2025 09:39:51 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:9:\"Comunidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=736109\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:127:\"WordPress Day Sevilla 2025: un 29 de noviembre de aprendizaje, ponencias y comunidad. ¡Todo el mundo es bienvenido al código!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"lualvarimp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6162:\"\n<p class=\"wp-block-paragraph\">Bienvenido, lector, a esta crónica, a esta gesta heroica en la que unos pocos elegidos transformaron con su sabiduría un día cualquiera en una experiencia única para el mundo.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Corría el día <strong>29 de noviembre del año 2025</strong> (D.C.) y el sol imperaba en el cielo, iluminando con intensidad la <strong>Ciudad del Conocimiento</strong>, ese solemne edificio donde se iba a celebrar un magno evento&#8230; Ese evento que elevaría aquella ciudad a los altares de la tecnología: <strong>el WordPress Day Sevilla 2025</strong>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">En aquella luminosa mañana de noviembre, cuando el aire aún no quemaba y el Guadalquivir se desperezaba, una espectacular idea flotaba en el ambiente sevillano: “<strong>Acercar la web y el mundo digital a todo el mundo.</strong>”</p>\n\n\n\n<p class=\"wp-block-paragraph\">Y así lo hicieron.&nbsp;</p>\n\n\n\n<p class=\"wp-block-paragraph\">En cuanto las puertas del incólume recinto se abrieron de par en par, los intrépidos ponentes y organizadores, los impertérritos paladines del conocimiento, se dispusieron a cumplir con su divino destino.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Desde una posición elevada, los patrocinadores observaban a la gente, invitando a todo ciudadano a disfrutar de la cultura y del bienhechor mecenazgo que estaban promoviendo para hacer de <strong>WordPress ese gran estandarte</strong> que guiaría a los participantes hacia nuevos e infinitos horizontes.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wpsevilla.org/wordpress-day-sevilla-2025/#entradas\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entradas</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">El clamor de la comunidad</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Todo había sido medido con meridiana precisión y, aunque cualquier vasallo podía acceder al lugar, ese evento iba <strong>dirigido oficiosos de DAW, DAM</strong> o ciclos formativos relacionados con la informática y el diseño web.</p>\n\n\n\n<p class=\"wp-block-paragraph\">El pueblo recibió con júbilo la noticia de que las puertas también estarían abiertas a todos los <strong>emprendedores y autónomos</strong> que quisieran mejorar su visibilidad online, a las <strong>empresas</strong> que buscaban captar más clientes y a las personas que estaban empezando y querían descubrir lo que WordPress podía hacer por ellas.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Y fue tras ese momento, en un alarde de virtuosa generosidad, cuando el supremo custodio de <strong>WordPress Day Sevilla 2025</strong>, en aquella luminosa mañana del <strong>29 de noviembre</strong> del año 2025 (D.C.), mirando con serenidad y magnificencia al vulgo desde el umbral de la <strong>Ciudad del Conocimiento</strong>, habló con impertérrita seguridad.</p>\n\n\n\n<p class=\"wp-block-paragraph\">“<em>Todos sois bienvenidos, porque no hace falta tener experiencia. Sólo ganas de aprender y participar.</em>”</p>\n\n\n\n<p class=\"wp-block-paragraph\">El pueblo llano estalló en una algarabía de felicidad, caminando con alborozo y de mutuo acuerdo hasta el edificio para desembolsar de buen gusto el coste simbólico de aquella entrada que tantos beneficios les iba a reportar: dos míseros euros destinados únicamente a asegurar la asistencia.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wpsevilla.org/wordpress-day-sevilla-2025/#entradas\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entradas</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">La erudición del sabio</h2>\n\n\n\n<p class=\"wp-block-paragraph\">El edificio acogió a la multitud entre la calidez de sus recios muros, donde colgaban los carteles de las ponencias que se iban a impartir por unos sabios de renombre: <strong>Lidia Marbán, Yannick García, Marina Brocca, Álvaro Gómez y Miguel Ángel Terrón</strong>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Las primeras presentaciones abarcaron cuestiones tan importantes como las de, <strong>¿por qué se necesitaba disponer de una web? ¿y qué se necesitaba para tener una?</strong>&#8230; Estas profundas reflexiones fueron explicadas con lucidez por los doctos ponentes y recibidas con sana clarividencia por la plebe.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Algunos mercaderes, asistentes al evento, se alegraron por estas explicaciones pero plantearon una cuestión crucial que les rondaba por la cabeza, porque ellos ya tenían su <strong>tienda online pero&#8230; ¿Y ahora qué?</strong>&nbsp;</p>\n\n\n\n<p class=\"wp-block-paragraph\">Una mujer prudente, maestra del saber, les invitó a participar en el discurso que se estaba preparando en aquel momento, para así solucionar todas sus preocupaciones. También les aconsejó acudir a las disertaciones magistrales de <strong>cómo abordar los requisitos legales imprescindibles para inspirar confianza en el negocio</strong>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Cerrando aquel ciclo de sabiduría, la exposición sobre los <strong>problemas de venta en la web</strong> dejó satisfechos a todos los asistentes que, tras un networking informal, marcharon a yantar y a reunirse con sus familias.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Habían asistido a un arduo y clarificador evento que los dejó exhaustos, pero felices ante las doctrinas obtenidas.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wpsevilla.org/wordpress-day-sevilla-2025/#entradas\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entradas</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Epílogo glorioso</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Y así es, querido lector, como un <strong>29 de noviembre del año 2025</strong> (D.C.), la <strong>Ciudad del Conocimiento</strong> se convirtió en el centro de la <strong>comunidad de WordPress</strong>, elevando a la muy noble ciudad de Sevilla a los altares de la tecnología.</p>\n\n\n\n<p class=\"wp-block-paragraph\">¡Larga vida a la ciudad de la Giralda!<br>¡Larga vida a <strong>WordPress Day Sevilla 2025</strong>!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wpsevilla.org/wordpress-day-sevilla-2025/#entradas\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entradas</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:100:\"https://es.wordpress.org/2025/11/26/wordpress-day-sevilla-2025-los-custodios-del-saber-digital/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"736109\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:79:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"WordPress 6.9 RC (candidata a definitiva) 1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"https://es.wordpress.org/2025/11/12/wordpress-6-9-rc-candidata-a-definitiva-1/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:86:\"https://es.wordpress.org/2025/11/12/wordpress-6-9-rc-candidata-a-definitiva-1/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 12 Nov 2025 20:03:18 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.9\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:2:\"RC\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=736103\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:336:\"¡La primera versión candidata (RC1) para WordPress 6.9 ya está lista para su descarga y prueba! Esta versión de WordPress aún está en desarrollo . No la instales, ejecutes ni pruebes en sitios web de producción o críticos. En su lugar, se recomienda evaluar RC1 en un servidor y sitio de pruebas. WordPress 6.9 RC1 se [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:11263:\"\n<p class=\"wp-block-paragraph\">¡La primera versión candidata (RC1) para WordPress 6.9 ya está lista para su descarga y prueba!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Esta versión de WordPress aún está en desarrollo</strong> . No la instales, ejecutes ni pruebes en sitios web de producción o críticos. En su lugar, se recomienda evaluar RC1 en un servidor y sitio de pruebas.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 6.9 RC1 se puede probar utilizando cualquiera de los siguientes métodos:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong>Plugin</strong></td><td>Instala y activa el plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">WordPress Beta Tester</a> en una instalación de WordPress. Selecciona el canal «Beta» y la transmisión «Solo Beta/ RC».</td></tr><tr><td><strong>Descarga directa</strong></td><td>Descarga la <a href=\"https://wordpress.org/wordpress-6.9-RC1.zip\" rel=\"nofollow\">versión RC1 (zip)</a> e instálala en un sitio web de WordPress.</td></tr><tr><td><strong>Línea de comandos</strong></td><td>Utiliza este comando <a href=\"https://make.wordpress.org/cli/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">WP-CLI</a> :<br><code>wp core update --version=6.9-RC1</code></td></tr><tr><td><strong>Campo de pruebas de WordPress</strong></td><td>Utiliza la  <a href=\"https://playground.wordpress.net/?php=8.3&amp;wp=beta&amp;networking=no&amp;language=&amp;multisite=no&amp;random=y4q1rn88xn\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">instancia de WordPress Playground 6.9 RC1</a> para probar el software directamente en tu navegador. No requiere configuración: ¡simplemente haz clic y listo! </td></tr></tbody></table></figure>\n\n\n\n<p class=\"wp-block-paragraph\">La fecha de lanzamiento definitiva prevista para WordPress 6.9 es <strong>el 2 de diciembre de 2025.</strong> El <a href=\"https://make.wordpress.org/core/6-9/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">calendario de lanzamientos completo se puede consultar aquí</a> . Tu ayuda probando las versiones Beta y RC es fundamental para que esta versión sea lo más estable y potente posible.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Por favor, continúa consultando el <a href=\"https://make.wordpress.org/core/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">blog Make WordPress Core</a> en las próximas semanas para obtener más información sobre <a href=\"https://make.wordpress.org/core/tag/6-9/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">las publicaciones relacionadas con la versión 6.9 .</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué novedades incluye WordPress 6.9 RC1?</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Consulta el <a href=\"https://es.wordpress.org/2022/09/22/wordpress-6-1-beta-1-ya-disponible/\" data-type=\"post\" data-id=\"115714\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">anuncio de la Beta 1</a> para obtener más detalles sobre WordPress 6.9.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Puedes consultar los detalles técnicos de todos los problemas abordados desde la Beta 4 utilizando estos enlaces:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/6.9?since=2025-11-07&amp;until=2025-11-11\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Commits de Gutenberg en la versión 6.9</a> desde el 7 de noviembre de 2025</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/log/?revs=61183-61203\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Cambios importantes en el núcleo para la versión 6.9</a> desde el 7 de noviembre de 2025</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=11%2F07%2F2025..11%2F11%2F2025&amp;milestone=6.9&amp;group=component&amp;col=id&amp;col=summary&amp;col=milestone&amp;col=changetime&amp;col=type&amp;order=id\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Tickets cerrados</a> desde el 7 de noviembre de 2025</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">¿Quieres saber más sobre esta versión? Aquí tienes algunos de los aspectos más destacados:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Mejoras en el editor del sitio y creación de contenido perfeccionada\n<ul class=\"wp-block-list\">\n<li>Capacidad para ocultar bloques</li>\n\n\n\n<li>Nuevos bloques</li>\n\n\n\n<li>Notas en bloques</li>\n\n\n\n<li>Paleta de comandos universal en wp-admin</li>\n</ul>\n</li>\n\n\n\n<li>Novedades para desarrolladores\n<ul class=\"wp-block-list\">\n<li>Mejoras de los componentes de vistas de datos y formularios de datos</li>\n\n\n\n<li>Nuevas funcionalidades en la API</li>\n\n\n\n<li>Actualizaciones de la API de interactividad</li>\n\n\n\n<li>Actualizaciones de la API de enlace de bloques</li>\n</ul>\n</li>\n\n\n\n<li>Mejoras de rendimiento\n<ul class=\"wp-block-list\">\n<li>Mejora en la gestión de scripts y estilos</li>\n\n\n\n<li>Consultas y almacenamiento en caché optimizadas</li>\n\n\n\n<li>Se ha añadido la capacidad de gestionar la «fetchpriority» en los módulos de ES y los mapas de importación.</li>\n\n\n\n<li>Estandarización del almacenamiento en búfer de salida</li>\n</ul>\n</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">El lanzamiento final está previsto para el 2 de diciembre. Como siempre, el éxito del lanzamiento depende de tu confirmación durante las pruebas. ¡Así que descarga y haz pruebas!</p>\n\n\n\n<h2 class=\"wp-block-heading\">Cómo puedes contribuir</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress es un software de código abierto posible gracias a una comunidad apasionada de personas que colaboran y contribuyen a su desarrollo. Los recursos que se presentan a continuación describen diversas maneras en que puedes ayudar a la plataforma web de código abierto más popular del mundo, independientemente de tus conocimientos técnicos.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Participa en las pruebas</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Realizar pruebas para detectar problemas es fundamental para el desarrollo de cualquier software. También es una forma valiosa para que cualquiera pueda contribuir.&nbsp;</p>\n\n\n\n<p class=\"wp-block-paragraph\">Tu ayuda para probar la versión RC1 de WordPress 6.9 es fundamental para garantizar que la versión final sea la mejor posible. Si bien probar el proceso de actualización es esencial, probar las nuevas funcionalidades es igualmente importante. Esta <a href=\"https://make.wordpress.org/test/2025/10/21/help-test-wordpress-6-9/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">guía detallada</a> te mostrará cómo probar las características de WordPress 6.9.</p>\n\n\n\n<h4 class=\"wp-block-heading\">Llamados a realizar pruebas</h4>\n\n\n\n<p class=\"wp-block-paragraph\">Gracias a todos los que ayudan a probar las siguientes mejoras y correcciones de errores:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/test/2025/10/06/call-for-testing-accordion-block/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Bloque de acordeón</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/test/2025/10/04/call-for-testing-ability-to-hide-blocks/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Capacidad para ocultar bloques</a></li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64099\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Estilos de bloques de carga de temas clásicos bajo demanda</a></li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64204\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Avisos de notas modificadas</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/10/abilities-api-in-wordpress-6-9/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">API de habilidades</a></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Si encuentras algún problema, infórmalo en la <a href=\"https://wordpress.org/support/forum/alphabeta/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">sección Alfa/Beta</a> de los foros de soporte o directamente en el <a href=\"https://core.trac.wordpress.org/newticket\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">WordPress Trac</a> si te sientes a gusto redactando un informe de error que permita reproducirlo. También puedes comprobar si tu problema coincide con la lista de <a href=\"https://core.trac.wordpress.org/tickets/major\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">errores conocidos</a> .</p>\n\n\n\n<p class=\"wp-block-paragraph\">¡Gracias a todos los que ayudan con las pruebas!</p>\n\n\n\n<h3 class=\"wp-block-heading\">Actualiza tu tema o plugin</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Para los autores de plugins y temas, sus productos desempeñan un papel fundamental en la ampliación de la funcionalidad y el valor de WordPress para todos los usuarios.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Gracias por seguir probando tus temas y plugins con las versiones beta de WordPress 6.9. Con RC1, deberás finalizar las pruebas y actualizar la versión <em>«Probado hasta» en </em><a href=\"https://developer.wordpress.org/plugins/wordpress-org/how-your-readme-txt-works/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">el archivo README de tu plugin</a> a la versión 6.9.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Si encuentras problemas de compatibilidad, publica información detallada en el <a href=\"https://wordpress.org/support/forum/alphabeta/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">foro de soporte</a> .</p>\n\n\n\n<h3 class=\"wp-block-heading\">Prueba en tus plataformas de alojamiento.</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Los servicios de alojamiento web proporcionan la infraestructura esencial para el soporte de WordPress y sus usuarios. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Las pruebas en los sistemas de alojamiento ayudan a fundamentar el proceso de desarrollo, a la vez que garantizan que WordPress y las plataformas de alojamiento sean totalmente compatibles, estén libres de errores, optimizadas para la mejor experiencia de usuario posible y que las actualizaciones se implementen en los sitios web de los clientes sin problemas.</p>\n\n\n\n<p class=\"wp-block-paragraph\">¿Quieres probar WordPress en tu sistema de alojamiento? <a href=\"https://make.wordpress.org/hosting/test-results-getting-started/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Empieza a configurar las pruebas de alojamiento distribuido aquí</a> . </p>\n\n\n\n<p class=\"wp-block-paragraph\">¡Gracias a todos <a href=\"https://make.wordpress.org/hosting/test-results/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">los proveedores de alojamiento web que ayudan a probar WordPress</a> !</p>\n\n\n\n<p class=\"wp-block-paragraph\">¿Tienes curiosidad por probar las versiones en general? Sigue las <a href=\"https://make.wordpress.org/test/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">iniciativas de pruebas en Make Core</a> y únete al <a href=\"https://wordpress.slack.com/messages/core-test/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">canal #core-test</a> en <a href=\"https://wordpress.slack.com/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Making WordPress Slack</a> .</p>\n\n\n\n<h2 class=\"wp-block-heading\">Un haiku para la RC1</h2>\n\n\n\n<pre class=\"wp-block-verse\"><em>Al amanecer</em> ,<br><em>RC1 rompe su cascarón</em><br><em>y emerge fuerte</em> .</pre>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://es.wordpress.org/2025/11/12/wordpress-6-9-rc-candidata-a-definitiva-1/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"736103\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"WordCamp Valencia 2025: Cuando eres Tech a tope\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://es.wordpress.org/2025/11/03/wordcamp-valencia-2025-cuando-eres-tech-a-tope/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:91:\"https://es.wordpress.org/2025/11/03/wordcamp-valencia-2025-cuando-eres-tech-a-tope/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 03 Nov 2025 15:28:21 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=733080\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:308:\"Venga, que ya sabes de qué te voy a hablar, así que siéntate, coge tu móvil y abre la aplicación de la agenda para marcar en negrita los días 8 y 9 de noviembre de 2025, porque tendrá lugar el WordPress Tech Congress… ¿Cómo?&#8230; ¿Que no sabes de qué hablo? ¡Menos mal que me tienes [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"lualvarimp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:8843:\"\n<p class=\"wp-block-paragraph\">Venga, que ya sabes de qué te voy a hablar, así que siéntate, coge tu móvil y abre la aplicación de la agenda para marcar en negrita los días 8 y 9 de noviembre de 2025, porque tendrá lugar el WordPress Tech Congress…</p>\n\n\n\n<p class=\"wp-block-paragraph\">¿Cómo?&#8230; ¿Que no sabes de qué hablo?</p>\n\n\n\n<p class=\"wp-block-paragraph\">¡Menos mal que me tienes aquí, escribiendo como un loco, para informarte de todas las cosas chulas que ocurren en torno a nuestro CMS preferido!</p>\n\n\n\n<h2 class=\"wp-block-heading\">La cita: ¿dónde y cuándo?</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Los días 8 y 9 de noviembre tendrá lugar la WordCamp Valencia 2025: WordPress Tech Congress</strong> así que, como ya tienes abierta la app de tu móvil, mueve los dedos sobre la pantalla y reserva ese fin de semana para disfrutar, <strong>en el Complejo Deportivo Cultural “La Petxina”</strong>, de lo mejorcito en ponencias que vas a ver en mucho tiempo.</p>\n\n\n\n<p class=\"wp-block-paragraph\">¿Y por qué debes ir? Pues mira… Lo primero, porque es Valencia y ya sabes lo que eso significa, aunque tire de topicazos: Esa rica paellita que sólo allí puedes comer, ese sol que ilumina los días de un modo diferente y, cómo no, ese ambientazo que se respira en cada poro de la ciudad.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Y si con esto no te he convencido, aquí va lo segundo…</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Esta WordCamp Valencia 2025: WordPress Tech Congress se ha puesto las pilas a lo bestia</strong> y va a ser un eventazo de esos que no olvidarás en tu vida, con dos salas simultaneando unas ponencias que te ayudarán en tus proyectos presentes y futuros, haciéndolos mucho mejores de lo que ya son (porque sé de sobra que, aunque no me lo quieras confesar, eres un auténtico pro de WordPress).</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://valencia.wordcamp.org/2025/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué te vas a encontrar? (la parte jugosa)</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Te vuelvo a recordar que <strong>la WordCamp Valencia 2025: WordPress Tech Congress tendrá lugar en el Complejo Deportivo Cultural “La Petxina” durante los días 8 y 9 de noviembre</strong> (vuelve a coger tu móvil por si acaso y confirma los datos, que nunca viene de más asegurarse).</p>\n\n\n\n<p class=\"wp-block-paragraph\">Bien, ¿dónde lo había dejado?&#8230; ¡Ah, sí!&#8230; Piensa en esas dos salas funcionando en paralelo a todo trapo durante el sábado, con unas charlas de lo más flipante y presentadas por unos ponentes que, si estuviéramos en un concierto de rock o de pop, serían las auténticas estrellas de la música.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Estos cracks de la ponencia <strong>vienen con unos perfiles variados, pero con una única misión: Instruirte (con teoría o casos reales) y, de paso, soltarte truquitos prácticos</strong>, de esos que, antes de abrir la libreta, ya te han dado cinco ideas geniales para implementar el lunes en ese proyecto que tienes entre manos.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Y entre estas charlas alucinantes encontrarás algunas como:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Potenciar WordPress</strong> con un agente de ecommerce</li>\n\n\n\n<li>Diseños que enganchan en <strong>la era de la IA</strong></li>\n\n\n\n<li><strong>SASS</strong> (el superviviente del apocalipsis CSS)</li>\n\n\n\n<li>Fidelizar y vender más con <strong>email marketing</strong></li>\n\n\n\n<li><strong>Sesgos cognitivos</strong> en el ecommerce</li>\n\n\n\n<li>Del SEO al AX</li>\n\n\n\n<li>Etc…</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Sé que la boca se te está haciendo agua, así que aprovecho de nuevo para decirte que <strong>la WordCamp Valencia 2025: WordPress Tech Congress tendrá lugar los días 8 y 9 de noviembre en el Complejo Deportivo Cultural “La Petxina”</strong> (esta vez no hace falta que revises la agenda del móvil, ya sé que lo has hecho bien).</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://valencia.wordcamp.org/2025/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Y después de aprender: ¡Fiesta, fiesta!</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Porque ya sabes de sobra que <strong>las WordCamp no son solo charlas, ponentes, comida</strong>, café y patrocinadores que te regalan chapas, pegatinas, tazas y camisetas…</p>\n\n\n\n<p class=\"wp-block-paragraph\">Por cierto, ¡qué maravilla los patrocinadores!&#8230; Que sepáis que nunca os olvido y que, sin vosotros, no sería posible que estos eventos pudieran hacerse o que las entradas al evento tuvieran un precio muy por debajo de lo que realmente valen… ¡Gracias, patrocinadores!</p>\n\n\n\n<p class=\"wp-block-paragraph\">Por cierto, ¿por dónde iba que me he “despistao”?&#8230; Ah, sí… Las charlas, los ponentes…</p>\n\n\n\n<p class=\"wp-block-paragraph\">Vas a acabar cansado pero muy satisfecho porque el sábado <strong>vas a aprender muchísimo y vas a conocer a gente que merece mucho la pena</strong> y con la que hasta puedes entablar relaciones profesionales (eso que llaman networking).</p>\n\n\n\n<p class=\"wp-block-paragraph\">Pero, si me admites un consejo, no te vayas aún a la cama, porque tras acabar las ponencias del sábado… ¡Comienza la fiesta!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Así que anímate y desconecta</strong> con el resto de asistentes tomando algo, y es que en Valencia hay vida nocturna que te está esperando. Y si eres de los formales y no quieres juerga nocturna, pues durante el evento, tras cada ponencia, hay también unas tertulias en los pasillos igual de valiosas.</p>\n\n\n\n<p class=\"wp-block-paragraph\">En definitiva, que <strong>lo importante es volver el lunes a tu casa con la batería recargada y con esas conversaciones que “inspiran” revoloteando por tu cerebro.</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://valencia.wordcamp.org/2025/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<p class=\"wp-block-paragraph\">Y ahora, inocente de ti, es cuando piensas que, como ya lo has dado todo durante el sábado (fiesta incluida), ya no tienes nada más que hacer… Pues que sepas que…</p>\n\n\n\n<h2 class=\"wp-block-heading\">¡El domingo no es momento de descansar!</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Por si te ha parecido poco lo del sábado, <strong>el domingo es el Contributor Day</strong>. Si nunca has ido a uno, te lo explico rapidito: <strong>Te vas a poner manos a la obra y a colaborar en proyectos para la comunidad WordPress</strong>, aparte de conocer a gente que contribuye en temas, traducciones, marketing y en otras cosas que quizás ni sabías que existían.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Y cuando llegues por fin a tu casa, sentirás esa gran y extraña satisfacción de:&nbsp;</p>\n\n\n\n<p class=\"wp-block-paragraph\">“<em>¡Qué guay! He hecho algo útil para la comunidad, pero sigo sin entender por qué me han puesto esa pegatina en el portátil, aunque para ser sincero, la verdad es que verla ahí me transmite un poco de orgullo</em>”.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Así que ya lo sabes. Si eres desarrollador, traductor, diseñador, creador de contenidos o simplemente un fan con muchas ganas de dejar huella, el Contributor Day es tu sitio.&nbsp;</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://valencia.wordcamp.org/2025/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Ya no me enrollo más</h2>\n\n\n\n<p class=\"wp-block-paragraph\">No hace falta que revises tu móvil, porque en tu agenda han quedado grabados a fuego <strong>los días 8 y 9 de noviembre, fecha en la que tendrá lugar la WordCamp Valencia 2025: WordPress Tech Congress, en el Complejo Deportivo Cultural “La Petxina”</strong>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Si todavía tienes dudas sobre si ir o no, te lo pongo bien clarito: <strong>Vas a aprender muchas cosas prácticas, vas a conocer gente alucinante y muy profesional, puedes colaborar en el Contributor Day</strong> y, sobre todo, pasar un finde espectacular en Valencia…</p>\n\n\n\n<p class=\"wp-block-paragraph\">Y seamos francos, <strong>un par de días en Valencia le mejoran a cualquiera el ánimo, así que compra tu entrada</strong>, reserva en tu agenda esos dos días y prepárate para decir a tu regreso eso de: “¿Os conté lo de la charla de…?”</p>\n\n\n\n<p class=\"wp-block-paragraph\">¡Vais a fardar un huevo!</p>\n\n\n\n<p class=\"wp-block-paragraph\">¡Nos vemos en La Petxina!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://valencia.wordcamp.org/2025/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://es.wordpress.org/2025/11/03/wordcamp-valencia-2025-cuando-eres-tech-a-tope/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"733080\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:30:\"https://es.wordpress.org/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:4:\"site\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"13096054\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";a:11:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Mon, 02 Mar 2026 17:14:46 GMT\";s:12:\"content-type\";s:34:\"application/rss+xml; charset=UTF-8\";s:4:\"vary\";s:37:\"Accept-Encoding, accept, content-type\";s:6:\"x-olaf\";s:3:\"⛄\";s:13:\"last-modified\";s:29:\"Thu, 26 Feb 2026 17:57:05 GMT\";s:4:\"link\";s:61:\"<https://es.wordpress.org/wp-json/>; rel=\"https://api.w.org/\"\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:4:\"gzip\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 2\";}s:5:\"build\";i:1760643936;s:21:\"cache_expiration_time\";i:1772514887;s:23:\"__cache_expiration_time\";i:1772514887;}', 'off');
